import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class Solution {
    void helper(int[] digits, ArrayList<Integer> current, Set<Integer> result, boolean[] used) {
        if (current.size() == digits.length) {
            int num = 0;
            for (int d : current) {
                num = num * 10 + d;
            }
            result.add(num);
            return;
        }
        for (int i = 0; i < digits.length; ++i) {
            if (!used[i]) {
                used[i] = true;
                current.add(digits[i]);
                helper(digits, current, result, used);
                current.remove(current.size() - 1);
                used[i] = false;
            }
        }
    }

    public List<Integer> uniquePermutations(int[] digits) {
        ArrayList<Integer> current = new ArrayList<>();
        Set<Integer> result = new HashSet<>();
        boolean[] used = new boolean[digits.length];
        java.util.Arrays.sort(digits);

        helper(digits, current, result, used);

        return result.stream().sorted().collect(Collectors.toList());
    }
}
```

